// src/App.js
import React, { useState } from "react";
import Dice from "react-dice-roll";

// --- Board Image ---
const boardImage = "/torahpoly_board.png";

/* ======================
   PROPERTY DEFINITIONS
====================== */

// --- RED ---
const schemYosephGardens = {
  type: "property",
  name: "Schem Yoseph Gardens",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemDreamResorts = {
  type: "property",
  name: "Schem Dream Resorts",
  colorGroup: "red",
  price: 300,
  rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- YELLOW ---
const ephraimHilltops = {
  type: "property",
  name: "Ephraim Hilltops",
  colorGroup: "yellow",
  price: 300,
  rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- GREEN ---
const gushKatif = {
  type: "property",
  name: "Gush Katif",
  colorGroup: "green",
  price: 350,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 1000 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const neveDekalim = {
  type: "property",
  name: "Neve Dekalim",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 200, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const ganOr = {
  type: "property",
  name: "Gan Or",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 100, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- PURPLE ---
const jerusalemHillsOrchard = {
  type: "property",
  name: "Jerusalem Hills Orchard",
  colorGroup: "purple",
  price: 100,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const jerusalemHills = {
  type: "property",
  name: "Jerusalem Hills",
  colorGroup: "purple",
  price: 100,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- GOLD ---
const hevronEloneiMamre = {
  type: "property",
  name: "Hevron Elonei Mamre",
  colorGroup: "gold",
  price: 400,
  rent: { base: 30, house1: 70, house2: 200, house3: 550, hotel: 650 },
  buildCost: { house: 80, hotel: 150 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronLuxuryCondos = {
  type: "property",
  name: "Hevron Luxury Condos",
  colorGroup: "gold",
  price: 400,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronHiTech = {
  type: "property",
  name: "Hevron Hi-Tech",
  colorGroup: "gold",
  price: 400,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

/* ======================
   BOARD EVENTS (PLACED)
====================== */

const boardEvents = {
  1: schemYosephGardens,
  3: schemRoyalEstates,
  4: schemDreamResorts,
  7: ephraimHilltops,

  11: gushKatif,
  12: neveDekalim,
  14: ganOr,

  28: jerusalemHillsOrchard,
  29: jerusalemHills,

  35: hevronEloneiMamre,
  37: hevronLuxuryCondos,
  38: hevronHiTech,
};



/* ======================
   BOARD GEOMETRY
====================== */

function buildBoardPositions(size = 700, margin = 60, perSide = 11) {
  const positions = [];
  const step = (size - 2 * margin) / (perSide - 1);

  // top
  for (let i = 0; i < perSide; i++)
    positions.push({ x: margin + i * step, y: margin });

  // right
  for (let i = 1; i < perSide; i++)
    positions.push({ x: size - margin, y: margin + i * step });

  // bottom
  for (let i = 1; i < perSide; i++)
    positions.push({ x: size - margin - i * step, y: size - margin });

  // left
  for (let i = 1; i < perSide - 1; i++)
    positions.push({ x: margin, y: size - margin - i * step });

  return positions.slice(0, 44);
}

const boardPositions = buildBoardPositions();

/* ======================
   PROPERTY MODAL
====================== */

function PropertyModal({ card, player, onBuy, onClose }) {
  if (!card) return null;

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        <h2>{card.name}</h2>
        <div
          style={{
            height: 16,
            background: card.colorGroup,
            borderRadius: 6,
            marginBottom: 10,
          }}
        />
        <p>Price: ${card.price}</p>
        <p>Rent: ${card.rent.base}</p>
        <p>1 House: ${card.rent.house1}</p>
        <p>2 Houses: ${card.rent.house2}</p>
        <p>3 Houses: ${card.rent.house3}</p>
        <p>Hotel: ${card.rent.hotel}</p>
        <p>Your money: ${player.money}</p>

        {card.ownerIndex === null && (
          <button onClick={onBuy} style={styles.buy}>
            Buy
          </button>
        )}

        <button onClick={onClose} style={styles.close}>
          Close
        </button>
      </div>
    </div>
  );
}

/* ======================
   MAIN APP
====================== */

function App() {
  const [players, setPlayers] = useState([
    { name: "Player 1", position: 0, money: 1500, color: "red" },
    { name: "Player 2", position: 0, money: 1500, color: "blue" },
  ]);

  const [currentPlayer, setCurrentPlayer] = useState(0);
  const [activeCard, setActiveCard] = useState(null);

  const rollDice = (value) => {
    setPlayers((prev) => {
      const updated = [...prev];
      let p = updated[currentPlayer];

      let newPos = (p.position + value) % 44;
      p.position = newPos;

      const landedCard = boardEvents[newPos];
      if (landedCard) setActiveCard(landedCard);

      return updated;
    });

    setCurrentPlayer((p) => (p + 1) % players.length);
  };

  const buyProperty = () => {
    setPlayers((prev) => {
      const updated = [...prev];
      const p = updated[currentPlayer];

      if (p.money >= activeCard.price) {
        p.money -= activeCard.price;
        activeCard.ownerIndex = currentPlayer;
      }
      return updated;
    });
    setActiveCard(null);
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h1>TorahPoly</h1>

      <div style={{ position: "relative", width: 700, margin: "auto" }}>
        <img src={boardImage} alt="Board" width={700} />

        {players.map((p, i) => {
          const pos = boardPositions[p.position];
          return (
            <div
              key={i}
              style={{
                position: "absolute",
                left: pos.x - 6,
                top: pos.y - 6,
                width: 12,
                height: 12,
                borderRadius: "50%",
                background: p.color,
              }}
            />
          );
        })}
      </div>

      <Dice onRoll={rollDice} />

      <p>
        Turn: {players[currentPlayer].name} | $
        {players[currentPlayer].money}
      </p>

      {activeCard && (
        <PropertyModal
          card={activeCard}
          player={players[currentPlayer]}
          onBuy={buyProperty}
          onClose={() => setActiveCard(null)}
        />
      )}
    </div>
  );
}

/* ======================
   STYLES
====================== */

const styles = {
  overlay: {
    position: "fixed",
    inset: 0,
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
  modal: {
    background: "#fff",
    padding: 20,
    borderRadius: 12,
    width: 300,
  },
  buy: {
    background: "green",
    color: "#fff",
    padding: "8px 12px",
    marginRight: 8,
    border: "none",
    borderRadius: 6,
    cursor: "pointer",
  },
  close: {
    padding: "8px 12px",
    borderRadius: 6,
    border: "none",
    cursor: "pointer",
  },
};

